import json
import os

import modal
import pandas as pd

app = modal.App("modal-nfs-etl-pipeline")

image = modal.Image.debian_slim().pip_install("pandas")
shared_volume = modal.Volume.from_name(
    "modal-nfs-etl-pipeline-vol", create_if_missing=True
)
secret = modal.Secret.from_name("modal-nfs-etl-pipeline-secret")


def _get_batch_size() -> int:
    batch_size = int(os.environ.get("BATCH_SIZE", "10"))
    return max(10, batch_size)


@app.function(
    image=image,
    volumes={"/shared": shared_volume},
    secrets=[secret],
)
def extract() -> int:
    batch_size = _get_batch_size()
    pipeline_id = os.environ.get("PIPELINE_ID", "unknown")

    data = {
        "record_id": list(range(1, batch_size + 1)),
        "category": ["alpha" if i % 2 == 0 else "beta" for i in range(batch_size)],
        "metric": [float(i) * 1.5 for i in range(batch_size)],
        "pipeline": [pipeline_id] * batch_size,
    }
    df = pd.DataFrame(data)
    df.to_csv("/shared/raw_data.csv", index=False)

    shared_volume.commit()
    return len(df)


@app.function(
    image=image,
    volumes={"/shared": shared_volume},
    secrets=[secret],
)
def transform() -> int:
    df = pd.read_csv("/shared/raw_data.csv")

    for column in df.select_dtypes(include=["object"]).columns:
        df[column] = df[column].str.upper()

    df["metric_double"] = df["metric"] * 2

    df.to_csv("/shared/transformed_data.csv", index=False)

    shared_volume.commit()
    return len(df)


@app.function(
    image=image,
    volumes={"/shared": shared_volume},
    secrets=[secret],
)
def load() -> int:
    df = pd.read_csv("/shared/transformed_data.csv")

    report = {
        "rows_processed": int(len(df)),
        "metric_mean": float(df["metric"].mean()),
        "metric_double_sum": float(df["metric_double"].sum()),
        "pipeline_id": os.environ.get("PIPELINE_ID", "unknown"),
    }

    with open("/shared/final_report.json", "w", encoding="utf-8") as handle:
        json.dump(report, handle, indent=2)

    shared_volume.commit()
    return len(df)


@app.local_entrypoint()
def main() -> None:
    rows_extracted = extract.remote()
    rows_transformed = transform.remote()
    rows_loaded = load.remote()

    output_dict = modal.Dict.from_name(
        "modal-nfs-etl-pipeline-output", create_if_missing=True
    )
    output_dict["rows_extracted"] = rows_extracted
    output_dict["rows_transformed"] = rows_transformed
    output_dict["rows_loaded"] = rows_loaded
    output_dict["pipeline_id"] = os.environ.get("PIPELINE_ID", "nfs-etl-2024")
    output_dict["report_path"] = "/shared/final_report.json"
